graphql.query:
query Recent($limit: Int!) {
  apiVersion
  runs(limit: $limit) {
    id
    target
    totalRequests
    state
    stats { samples p50Micros p99Micros p999Micros }
    throughput { requestsPerSec megabitsPerSec }
    startedAt
    finishedAt
  }
}

query Run($id: String!) {
  run(id: $id) {
    id
    state
    completed
    failureReason
    stats { samples minNs meanNs p50Ns p90Ns p99Ns p999Ns maxNs }
    throughput { requestsPerSec bytesPerSec megabitsPerSec }
  }
}

subscription {
  runProgress {
    kind
    runId
    total
    completed
    failureReason
    stats { samples p50Micros p99Micros }
    throughput { requestsPerSec }
    at
  }
}
